        const _s = std.fmt.allocPrint(std.heap.page_allocator, "{s} {d}\n", .{ e.key_ptr.*, us }) catch continue;
        defer std.heap.page_allocator.free(_s);
        _stdout.writeStreamingAll(_io, _s) catch {};
    }
}
